examples.original_ir:
define float @test_select_fadd(i1 %cond, float %A, float %B) {
  %add = fadd float %A, %B
  %res = select ninf i1 %cond, float %add, float %A
  ret float %res
}

examples.optimized_ir:
define float @test_select_fadd(i1 %cond, float %A, float %B) {
  %1 = select ninf i1 %cond, float %B, float -0.000000e+00
  %res = fadd float %A, %1
  ret float %res
}
